class Solution:
    def findAnagrams(self, s: str, p: str) -> List[int]:
        m, n = len(p), len(s)
        if m > n: return []
        need = [0]*26; have = [0]*26
        for c in p: need[ord(c)-97] += 1
        ans = []
        for i, c in enumerate(s):
            have[ord(c)-97] += 1
            if i >= m: have[ord(s[i-m])-97] -= 1
            if i >= m-1 and have == need: ans.append(i-m+1)
        return ans

