class Solution {
public:
    vector<int> findAnagrams(string s, string p) {
        int m=p.size(), n=s.size(); vector<int> ans;
        if(m>n) return ans;
        int need[26]={}, have[26]={};
        for(char c:p) need[c-'a']++;
        for(int i=0;i<n;i++){
            have[s[i]-'a']++;
            if(i>=m) have[s[i-m]-'a']--;
            if(i>=m-1){
                int ok=1; for(int j=0;j<26;j++) if(have[j]!=need[j]){ok=0;break;}
                if(ok) ans.push_back(i-m+1);
            }
        }
        return ans;
    }
};

