int* findAnagrams(char* s, char* p, int* rs) {
    int m=strlen(p), n=strlen(s); *rs=0;
    if(m>n) return NULL;
    int need[26]={0}, have[26]={0};
    for(int i=0;p[i];i++) need[p[i]-'a']++;
    int* ans=malloc(n*sizeof(int));
    for(int i=0;s[i];i++){
        have[s[i]-'a']++;
        if(i>=m) have[s[i-m]-'a']--;
        if(i>=m-1){
            int ok=1; for(int j=0;j<26;j++) if(have[j]!=need[j]){ok=0;break;}
            if(ok) ans[(*rs)++]=i-m+1;
        }
    }
    return ans;
}
